B.OG=new A.F(B.k,["Technical University in Dortmund","Technische Universit\xe4t Dortmund"],t.w)
B.Pg=new A.F(B.k,[u.A,"Studiengang: Wirtschaftsingenieurwesen (B.Sc.)\nProfil: Management elektrischer Systeme"],t.w)
B.Ov=new A.F(B.k,[u.g,"Workshop zu 3D-Druck und Laser-Holzschneider"],t.w)
B.Nx=new A.F(B.k,["Programming of a Micro Controller ","Programmierung eines Mikrocontrollers "],t.w)
